package com.oneil.wellness.walkplanner.calendar.persistence;
import static org.junit.jupiter.api.Assertions.*;import com.oneil.wellness.walkplanner.calendar.model.*;import java.util.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.dao.DataIntegrityViolationException;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.transaction.annotation.Transactional;
@SpringBootTest @Transactional class ProviderPersistenceTest {
 @Autowired ProviderConnectionService service;@Autowired CalendarProviderConnectionRepository connections;@Autowired JdbcTemplate jdbc;
 @Test void migrationCreatesSchemaAndConnectionIsUnique(){assertEquals(1,jdbc.queryForObject("select count(*) from flyway_schema_history where success=true and version='1'",Integer.class));var first=service.getOrCreate(CalendarProviderType.CALDAV,"CalDAV",true);var second=service.getOrCreate(CalendarProviderType.CALDAV,"Other",false);assertEquals(first.getId(),second.getId());assertEquals(1,connections.findAll().stream().filter(c->c.getProviderType()==CalendarProviderType.CALDAV).count());}
 @Test void selectedCalendarsAreDurable(){var calendars=List.of(new CalendarDescriptor(CalendarProviderType.CALDAV,"one","One",null,true,true,true,false,null,null),new CalendarDescriptor(CalendarProviderType.CALDAV,"two","Two",null,true,true,true,false,null,null));service.persistSelections(CalendarProviderType.CALDAV,calendars,Set.of("two"));assertEquals(Set.of("two"),service.selectedIds(CalendarProviderType.CALDAV));service.persistSelections(CalendarProviderType.CALDAV,calendars,Set.of("one"));assertEquals(Set.of("one"),service.selectedIds(CalendarProviderType.CALDAV));}
}
